    hotels:[{name:"开封亚朵酒店",brand:"亚朵酒店",area:"开封市中心",price:"400-1200元/晚",fit:"交通便利，出行方便"},{name:"开封桔子酒店",brand:"桔子酒店",area:"开封火车站附近",price:"200-600元/晚",fit:"靠近交通枢纽，中转便捷"},{name:"开封格林豪泰酒店",brand:"格林豪泰酒店",area:"开封商业区",price:"150-400元/晚",fit:"商圈核心，购物美食集中"}],
